import React from "react";
import "./HomePage.css";
import logo from '../../icons/logo.png';
import { useNavigate } from "react-router-dom";

export const HomePage: React.FC = () => {
  const navigate = useNavigate();
  return (
    <div className="page-wrapper">
      <div className="header">
        <span><img className="logo-icon" src={logo} alt="logo" /></span>
        <div className="brand-name">
          HORAND
          <br />
          Partnership
        </div>
      </div>

      <div className="hero-section">
        <h1 className="hero-title">
          Ми допоможемо Вам почати побудувати бізнес разом
        </h1>
        <p className="hero-description">
          Ми допоможемо визначити долю кожного зі співвласників, розподіл
          частки майбутніх доходів, розподіл доходів з проектів або розподіл
          частки доходів з клієнтів.
        </p>
      </div>

      <button className="cta-button" onClick={() => navigate("/login")}>Get Started</button>

      <p className="footer-text">Streamline your inventory process today</p>
    </div>
  );
};
